<?php $dir = __DIR__ . "/app/Filament"; $iterator = new RecursiveIteratorIterator(new RecursiveDirectoryIterator($dir)); $regex = new RegexIterator($iterator, "/^.+\.php$/i", RecursiveRegexIterator::GET_MATCH); foreach ($regex as $file) { $path = $file[0]; $content = file_get_contents($path); $newContent = preg_replace("/->dateTime\(\)/", "->dateTime('d M Y, h:i A')", $content); $newContent = preg_replace("/DateTimePicker::make\('([^']+)'\)/", "DateTimePicker::make('$1')->displayFormat('d M Y, h:i A')", $newContent); if ($content !== $newContent) { file_put_contents($path, $newContent); } } echo "Done replacing dateTime formats.\n";
